import { Injectable } from '@angular/core';
import { HttpClient, HttpHeaders } from "@angular/common/http";
import { APIkey } from "./key";

@Injectable({
  providedIn: 'root'
})
export class NewsService {

  constructor(private http:HttpClient) { }
  
  url="https://cors-anywhere.herokuapp.com/https://newsapi.org/v2/everything?q=covid19 OR covid-19 OR coronavirus&language=en&pageSize=100&sortBy=popularity&page=1"//&apiKey="+APIkey;
  option={
    headers:new HttpHeaders({
      'x-requested-with':'patelsajan.github.io',
      'X-Api-Key':APIkey
    })
  }

  getNews(){
  return this.http.get<any>(this.url,this.option);
  }

  countryNews(country:string){
    console.log(country)
    return this.http.get<any>("https://newsapi.org/v2/top-headlines?country="+country+"&apiKey="+APIkey+"&language=en");
  }
}
